import { type ReactNode, useCallback } from "react";
import { RouterProvider as AriaRouterProvider } from "react-aria-components";

/**
 * Options intercepted by RouterProvider before delegating to the user's router.
 */
export interface DSRouterOptions {
  /**
   * Use full browser navigation instead of client-side routing.
   * When true, the href is used as-is (transformHref is not applied).
   */
  fullPageNavigation?: boolean | undefined;
}

declare module "react-aria-components" {
  interface RouterConfig {
    routerOptions: DSRouterOptions;
  }
}

export interface RouterProviderProps {
  children: ReactNode;
  /**
   * Function to perform client-side navigation.
   * Not called when `fullPageNavigation: true` is specified.
   */
  navigate: (href: string) => void;
  /**
   * Transforms hrefs before rendering them in the DOM.
   *
   * Use this to replicate Next.js Link behavior when your app has a `basePath` configured.
   * Next.js automatically prepends `basePath` to links, but since DS components use their
   * own Link implementation, you need to provide this transformation manually.
   *
   * Not applied when `fullPageNavigation: true` (those hrefs should already include the full path).
   *
   * @example
   * // Prepend basePath for Next.js apps
   * transformHref={(href) => router.basePath + href}
   */
  transformHref?: (href: string) => string;
}

/**
 * Provides client-side routing context for design system components.
 *
 * @see {@link https://one-design-system-c63ef4.gitlab.io/?path=/docs/utilities-routerprovider--docs | Storybook documentation}
 */
export function RouterProvider({
  children,
  navigate,
  transformHref,
}: RouterProviderProps) {
  const smartNavigate = useCallback(
    (href: string, routerOptions?: DSRouterOptions) => {
      // fullPageNavigation: use browser navigation with href as-is
      if (routerOptions?.fullPageNavigation) {
        window.location.href = href;
        return;
      }

      navigate(href);
    },
    [navigate]
  );

  return (
    <AriaRouterProvider
      navigate={smartNavigate}
      {...(transformHref ? { useHref: transformHref } : {})}
    >
      {children}
    </AriaRouterProvider>
  );
}

RouterProvider.displayName = "RouterProvider";
